from typing import List

def string_to_int(string: str, alphabet: List[str]) -> int:

    base = len(alphabet)
    char_to_value = {char: idx for idx, char in enumerate(alphabet)}
    result = 0
    for char in string:
        result = result * base + char_to_value[char]
    return result

